226	// collectAuthZClaimSets collects all ClaimSets from AuthZConfigs
227	// and returns a slice sorted by variable name for a deterministic output.
228	func collectAuthZClaimSets(authZConfigs []*dataplane.AuthZConfig) []ClaimSet {
229		if len(authZConfigs) == 0 {
230			return nil
231		}
232	
233		seen := make(map[string][]string)
234	
235		for _, cfg := range authZConfigs {
236			if cfg == nil {
237				continue
238			}
239			for k, v := range cfg.AuthClaimSets {
240				if _, exists := seen[k]; !exists {
241					seen[k] = v
242				}
243			}
244		}
245	
246		if len(seen) == 0 {
247			return nil
248		}
249	
250		result := make([]ClaimSet, 0, len(seen))
251		for variable, claims := range seen {
252			result = append(result, ClaimSet{Variable: variable, Claims: claims})
253		}
254	
255		sort.Slice(result, func(i, j int) bool {
256			return result[i].Variable < result[j].Variable
257		})
258	
259		return result
260	}
