273	// buildHTTPSSL converts a dataplane SSL config into an http.SSL config,
274	// generating the PEM file paths for each certificate/key pair.
275	func buildHTTPSSL(ssl *dataplane.SSL) *http.SSL {
276		certs := make([]string, 0, len(ssl.KeyPairIDs))
277		keys := make([]string, 0, len(ssl.KeyPairIDs))
278	
279		var sslCertificateID string
280	
281		for _, id := range ssl.KeyPairIDs {
282			pemFile := generatePEMFileName(id)
283			certs = append(certs, pemFile)
284			keys = append(keys, pemFile)
285		}
286	
287		// ClientCertBundleID can be empty for mode: AllowInsecureFallback
288		// In this case, we don't want to generate an ID.
289		if ssl.ClientCertBundleID != "" {
290			sslCertificateID = generateCertBundleFileName(ssl.ClientCertBundleID)
291		}
292	
293		return &http.SSL{
294			Certificates:        certs,
295			CertificateKeys:     keys,
296			Protocols:           ssl.Protocols,
297			Ciphers:             ssl.Ciphers,
298			PreferServerCiphers: ssl.PreferServerCiphers,
299			ClientCertificate:   sslCertificateID,
300			VerifyClient:        string(ssl.VerifyClient),
301			RequireVerifiedCert: ssl.RequireVerifiedCert,
302		}
303	}
