357	// extractMirrorTargetsWithPercentages extracts mirror targets and their percentages from path rules.
358	func extractMirrorTargetsWithPercentages(pathRules []dataplane.PathRule) map[string]*float64 {
359		mirrorTargets := make(map[string]*float64)
360	
361		for _, rule := range pathRules {
362			for _, matchRule := range rule.MatchRules {
363				for _, mirrorFilter := range matchRule.Filters.RequestMirrors {
364					if mirrorFilter.Target != nil {
365						if mirrorFilter.Percent == nil {
366							mirrorTargets[*mirrorFilter.Target] = helpers.GetPointer(100.0)
367							continue
368						}
369	
370						percentage := mirrorFilter.Percent
371	
372						if _, exists := mirrorTargets[*mirrorFilter.Target]; !exists ||
373							*percentage > *mirrorTargets[*mirrorFilter.Target] {
374							mirrorTargets[*mirrorFilter.Target] = percentage // set a higher percentage if it exists
375						}
376					}
377				}
378			}
379		}
380	
381		return mirrorTargets
382	}
