963	func needsInternalLocationsForMatches(rule dataplane.PathRule) bool {
964		if len(rule.MatchRules) > 1 {
965			return true
966		}
967	
968		return len(rule.MatchRules) == 1 && !isPathOnlyMatch(rule.MatchRules[0].Match)
