971	// pathAndTypeMap contains a map of paths and any path types defined for that path
972	// for example, {/foo: {exact: {}, prefix: {}}}.
973	type pathAndTypeMap map[string]map[dataplane.PathType]struct{}
974	
975	func getMaxLocationCountAndPathMap(pathRules []dataplane.PathRule) (int, pathAndTypeMap) {
976		// To calculate the maximum number of locations, we need to take into account the following:
977		// 1. Each path rule will have at least one external location.
978		// 2. Each path rule may have an additional external location if it's a non-slashed prefix path.
979		// 3. There may be an additional location for the default root path.
980		// 4. For inference backends:
981		//    - Single backend without matches: 2 locations (external EPP + internal proxy pass)
982		//    - Single backend with matches: 3 locations (external redirect + internal EPP + internal proxy pass)
983		//    - Multiple backends without matches: 1 external + (2 * numBackends) internal locations
984		//    - Multiple backends with matches: 1 external + 1 split clients + (2 * numBackends) internal locations
985		// 5. For non-inference backends with matches:
986		//    - Each match rule gets an internal location
987		// We also return a map of all paths and their types.
988	
989		maxLocs := 0
990		pathsAndTypes := make(pathAndTypeMap)
991	
992		for _, rule := range pathRules {
993			// External locations calculation
994			maxLocs++ // Base external location for the path
995	
996			// Add the path to the map
997			if pathsAndTypes[rule.Path] == nil {
998				pathsAndTypes[rule.Path] = make(map[dataplane.PathType]struct{})
999			}
1000			pathsAndTypes[rule.Path][rule.PathType] = struct{}{}
1001	
1002			// Check if we need an additional external location for non-slashed prefix paths
1003			if isNonSlashedPrefixPath(rule.PathType, rule.Path) {
1004				maxLocs++ // Additional external location for exact match
1005			}
1006	
1007			// Determine if we need internal locations for matches
1008			needsInternalMatches := needsInternalLocationsForMatches(rule)
1009	
1010			// Internal locations calculation
1011			for _, matchRule := range rule.MatchRules {
1012				if !rule.HasInferenceBackends {
1013					// Non-inference backends with matches need internal locations
1014					if needsInternalMatches {
1015						maxLocs++ // Internal match location per match rule
1016					}
1017				} else {
1018					// Inference backends calculation
1019					numBackends := len(matchRule.BackendGroup.Backends)
1020	
1021					if needsInternalMatches {
1022						// Has HTTP matching conditions
1023						if numBackends > 1 {
1024							// Multiple backends with matches: split clients + 2 locations per backend
1025							maxLocs++                  // Internal split clients location
1026							maxLocs += numBackends * 2 // EPP + proxy pass per backend
1027						} else {
1028							// Single backend with matches: EPP + proxy pass
1029							maxLocs += 2
1030						}
1031					} else {
1032						// No HTTP matching conditions
1033						if numBackends > 1 {
1034							// Multiple backends without matches: 2 locations per backend (no split clients for external)
1035							maxLocs += numBackends * 2 // EPP + proxy pass per backend
1036						} else {
1037							// Single backend without matches: proxy pass only (external becomes EPP)
1038							maxLocs++ // Just the internal proxy pass location
1039						}
1040					}
1041				}
1042			}
1043		}
1044	
1045		// Add 1 for potential default root location
1046		maxLocs++
1047	
1048		return maxLocs, pathsAndTypes
1049	}
1050	
1051	func initializeExternalLocations(
1052		rule dataplane.PathRule,
1053		pathsAndTypes pathAndTypeMap,
1054	) []http.Location {
1055		extLocations := make([]http.Location, 0, 2)
1056		locType := getLocationTypeForPathRule(rule)
1057		externalLocPath := createPath(rule)
1058	
1059		// If the path type is Prefix and doesn't contain a trailing slash, then we need a second location
1060		// that handles the Exact prefix case (if it doesn't already exist), and the first location is updated
1061		// to handle the trailing slash prefix case (if it doesn't already exist)
1062		if isNonSlashedPrefixPath(rule.PathType, externalLocPath) {
1063			// if Exact path and/or trailing slash Prefix path already exists, this means some routing rule
1064			// configures it. The routing rule location has priority over this location, so we don't try to
1065			// overwrite it and we don't add a duplicate location to NGINX because that will cause an NGINX config error.
1066			_, exactPathExists := pathsAndTypes[rule.Path][dataplane.PathTypeExact]
1067			var trailingSlashPrefixPathExists bool
1068			if pathTypes, exists := pathsAndTypes[rule.Path+"/"]; exists {
1069				_, trailingSlashPrefixPathExists = pathTypes[dataplane.PathTypePrefix]
1070			}
1071	
1072			if exactPathExists && trailingSlashPrefixPathExists {
1073				return []http.Location{}
1074			}
1075	
1076			if !trailingSlashPrefixPathExists {
1077				externalLocTrailing := http.Location{
1078					Path: externalLocPath + "/",
1079					Type: locType,
1080				}
1081				extLocations = append(extLocations, externalLocTrailing)
1082			}
1083			if !exactPathExists {
1084				externalLocExact := http.Location{
1085					Path: exactPath(rule.Path),
1086					Type: locType,
1087				}
1088				extLocations = append(extLocations, externalLocExact)
1089			}
1090		} else {
1091			externalLoc := http.Location{
1092				Path: externalLocPath,
1093				Type: locType,
1094			}
1095			extLocations = []http.Location{externalLoc}
1096		}
1097	
1098		return extLocations
1099	}
