1192	// updateLocation updates a location with any relevant configurations, like proxy_pass, filters, tls settings, etc.
1193	func updateLocation(
1194		matchRule dataplane.MatchRule,
1195		pathRule dataplane.PathRule,
1196		location http.Location,
1197		listenerPort int32,
1198		keepAliveCheck keepAliveChecker,
1199		disableBaseProxySetHeaders []string,
1200		mirrorPercentage *float64,
1201		serverID string,
1202		matchRuleIndex int,
1203		pathRuleIndex int,
1204	) http.Location {
1205		filters := matchRule.Filters
1206		grpc := pathRule.GRPC
1207		inferenceBackend := pathRule.HasInferenceBackends
1208	
1209		if filters.InvalidFilter != nil {
1210			location.Return = &http.Return{Code: http.StatusInternalServerError}
1211			return location
1212		}
1213	
1214		location = updateLocationMirrorRoute(location, pathRule.Path, grpc)
1215		location.Includes = append(location.Includes, createIncludesFromLocationSnippetsFilters(filters.SnippetsFilters)...)
1216		location = updateLocationAuthenticationFilter(location, filters.AuthenticationFilter)
1217		location = updateLocationExternalAuthFilter(location, filters.ExternalAuthFilter)
1218		location = updateLocationCORSFilter(location, filters.CORSFilter, serverID, pathRuleIndex, matchRuleIndex)
1219	
1220		if filters.RequestRedirect != nil {
1221			return updateLocationRedirectFilter(location, filters.RequestRedirect, listenerPort, pathRule)
1222		}
1223	
1224		location = updateLocationRewriteFilter(location, filters.RequestURLRewrite, pathRule)
1225		location = updateLocationMirrorFilters(location, filters.RequestMirrors, pathRule.Path, mirrorPercentage)
1226		location = updateLocationProxySettings(
1227			location,
1228			matchRule,
1229			grpc,
1230			inferenceBackend,
1231			keepAliveCheck,
1232			disableBaseProxySetHeaders,
1233		)
1234	
1235		return location
1236	}
