1449	// extractUniqueJWKSLocations extracts unique internal JWKS locations from a list of locations.
1450	// This prevents duplicate NGINX location blocks when multiple locations reference the same AuthenticationFilter.
1451	func extractUniqueJWKSLocations(locations []http.Location) []http.Location {
1452		seen := make(map[string]string) // map of path to remoteURI
1453		var result []http.Location
1454	
1455		for _, loc := range locations {
1456			if loc.AuthJWT != nil && loc.AuthJWT.Remote != nil {
1457				path := loc.AuthJWT.Remote.Path
1458	
1459				if _, exists := seen[path]; !exists {
1460					seen[path] = loc.AuthJWT.Remote.URI
1461	
1462					jwksLocation := http.Location{
1463						Path:      path,
1464						Type:      http.InternalLocationType,
1465						ProxyPass: loc.AuthJWT.Remote.URI,
1466					}
1467	
1468					if loc.AuthJWT.Remote.TrustedCertificate != "" {
1469						jwksLocation.ProxySSLVerify = &http.ProxySSLVerify{
1470							TrustedCertificate: loc.AuthJWT.Remote.TrustedCertificate,
1471						}
1472					}
1473	
1474					result = append(result, jwksLocation)
1475				}
1476			}
1477		}
1478	
1479		return result
1480	}
