1599	// resolveProxyHTTPVersion decides whether to emit a proxy_http_version directive for a location.
1600	// The directive is only written when the value differs from NGINX's default (1.1).
1601	//
1602	// Priority:
1603	//  1. All valid backends carry appProtocol kubernetes.io/h2c → return "2".
1604	//  2. Otherwise → return "" (omit directive; NGINX default of 1.1 applies).
1605	//
1606	// h2c detection is skipped for gRPC locations because grpc_pass handles HTTP/2 internally.
1607	func resolveProxyHTTPVersion(backends []dataplane.Backend, grpc bool) string {
1608		if !grpc && allValidBackendsAreH2C(backends) {
1609			return "2"
1610		}
1611	
1612		return ""
1613	}
1614	
1615	// allValidBackendsAreH2C returns true when at least one valid backend exists and every
1616	// valid backend has AppProtocol kubernetes.io/h2c.
1617	func allValidBackendsAreH2C(backends []dataplane.Backend) bool {
1618		hasValid := false
1619		for _, b := range backends {
1620			if !b.Valid {
1621				continue
1622			}
1623			if b.AppProtocol != graph.AppProtocolTypeH2C {
1624				return false
1625			}
1626			hasValid = true
1627		}
1628		return hasValid
1629	}
