1665	func generateProtocolString(ssl *http.ProxySSLVerify, grpc bool) string {
1666		if !grpc {
1667			if ssl != nil {
1668				return "https"
1669			}
1670			return "http"
1671		}
1672		if ssl != nil {
1673			return "grpcs"
1674		}
1675		return "grpc"
1676	}
