1863	func createRouteMatch(match dataplane.Match, redirectPath string) routeMatch {
1864		hm := routeMatch{
1865			RedirectPath: redirectPath,
1866		}
1867	
1868		if isPathOnlyMatch(match) {
1869			hm.Any = true
1870			return hm
1871		}
1872	
1873		if match.Method != nil {
1874			hm.Method = *match.Method
1875		}
1876	
1877		if match.Headers != nil {
1878			headers := make([]string, 0, len(match.Headers))
1879			headerNames := make(map[string]struct{})
1880	
1881			for _, h := range match.Headers {
1882				// duplicate header names are not permitted by the spec
1883				// only configure the first entry for every header name (case-insensitive)
1884				lowerName := strings.ToLower(h.Name)
1885				if _, ok := headerNames[lowerName]; !ok {
1886					headers = append(headers, createHeaderKeyValString(h))
1887					headerNames[lowerName] = struct{}{}
1888				}
1889			}
1890			hm.Headers = headers
1891		}
1892	
1893		if match.QueryParams != nil {
1894			params := make([]string, 0, len(match.QueryParams))
1895	
1896			for _, p := range match.QueryParams {
1897				params = append(params, createQueryParamKeyValString(p))
1898			}
1899			hm.QueryParams = params
1900		}
1901	
1902		return hm
1903	}
