1989		if filters == nil || filters.RequestHeaderModifiers == nil {
1990			return baseHeaders
1991		}
1992	
1993		headerFilter := filters.RequestHeaderModifiers
1994	
1995		headerLen := len(headerFilter.Add) + len(headerFilter.Set) + len(headerFilter.Remove) + len(baseHeaders)
1996		proxySetHeaders := make([]http.Header, 0, headerLen)
1997		if len(headerFilter.Add) > 0 {
1998			addHeaders := createHeadersWithVarName(headerFilter.Add)
1999			proxySetHeaders = append(proxySetHeaders, addHeaders...)
2000		}
2001		if len(headerFilter.Set) > 0 {
2002			setHeaders := createHeaders(headerFilter.Set)
2003			proxySetHeaders = append(proxySetHeaders, setHeaders...)
2004		}
2005		// If the value of a header field is an empty string then this field will not be passed to a proxied server
