45		port     int32
46	}
47	
48	func createStreamServers(logger logr.Logger, conf dataplane.Configuration) []stream.Server {
49		totalServers := len(conf.TLSServers) + len(conf.TCPServers) + len(conf.UDPServers)
50		if totalServers == 0 {
51			return nil
52		}
53	
54		streamServers := make([]stream.Server, 0, totalServers*2)
55		portSet := make(map[portProtoKey]struct{})
56		upstreams := make(map[string]dataplane.Upstream)
