58		for _, u := range conf.StreamUpstreams {
59			upstreams[u.Name] = u
60		}
61	
62		for _, server := range conf.TLSServers {
63			if server.SSL != nil {
64				// TLS Terminate mode: create a socket server with SSL termination
65				streamServers = append(streamServers, createTLSTerminateSocketServer(server, upstreams, conf)...)
66			} else if len(server.Upstreams) > 0 {
67				// TLS Passthrough mode: create a socket server that proxies encrypted traffic
68				upstreamName := server.Upstreams[0].Name
