84			key := portProtoKey{port: server.Port, protocol: string(v1.TCPProtocolType)}
85			if _, inPortSet := portSet[key]; inPortSet {
86				continue
87			}
88	
89			portSet[key] = struct{}{}
90	
91			// we do not evaluate rewriteClientIP settings for non-socket stream servers
92			streamServer := stream.Server{
93				Listen:     fmt.Sprint(server.Port),
94				StatusZone: server.Hostname,
95				Target:     getTLSPassthroughVarName(server.Port),
96				SSLPreread: true,
97			}
98			streamServers = append(streamServers, streamServer)
99		}
100	
101		// Process Layer4 servers (TCP and UDP)
102		processLayer4Servers(logger, conf.TCPServers, upstreams, portSet, &streamServers, string(v1.TCPProtocolType))
103		processLayer4Servers(logger, conf.UDPServers, upstreams, portSet, &streamServers, string(v1.UDPProtocolType))
104	
105		return streamServers
106	}
107	
108	// processLayer4Servers processes TCP and UDP servers to create stream servers.
109	func processLayer4Servers(
110		logger logr.Logger,
111		servers []dataplane.Layer4VirtualServer,
112		upstreams map[string]dataplane.Upstream,
113		portSet map[portProtoKey]struct{},
114		streamServers *[]stream.Server,
115		protocol string,
116	) {
117		protocolSuffix := ""
118		if protocol == string(v1.UDPProtocolType) {
119			protocolSuffix = " " + strings.ToLower(string(v1.UDPProtocolType))
120		}
121	
122		for i, server := range servers {
123			key := portProtoKey{port: server.Port, protocol: protocol}
124			if _, inPortSet := portSet[key]; inPortSet {
125				continue
126			}
127	
128			if len(server.Upstreams) == 0 {
129				logger.V(1).Info(
130					fmt.Sprintf("%s Server skipped - no upstreams", protocol),
131					"serverIndex", i,
132					"port", server.Port,
133				)
134				continue
135			}
136	
137			var proxyPass string
138			if len(server.Upstreams) > 1 {
139				proxyPass = fmt.Sprintf("$backend_%d", server.Port)
140				hasValidUpstreams := false
141				for _, upstream := range server.Upstreams {
142					if u, ok := upstreams[upstream.Name]; ok && len(u.Endpoints) > 0 {
143						hasValidUpstreams = true
144						break
145					}
146				}
147				if !hasValidUpstreams {
148					logger.V(1).Info(
149						fmt.Sprintf("%s Server skipped - no valid upstreams with endpoints", protocol),
150						"serverIndex", i,
151						"port", server.Port,
152					)
153					continue
154				}
155			} else {
156				upstreamName := server.Upstreams[0].Name
157				if u, ok := upstreams[upstreamName]; ok && len(u.Endpoints) > 0 {
158					proxyPass = upstreamName
159				} else {
160					logger.V(1).Info(
161						fmt.Sprintf("%s Server skipped - upstream not found or no endpoints", protocol),
162						"serverIndex", i,
163						"port", server.Port,
164						"upstreamName", upstreamName,
165					)
166					continue
167				}
168			}
169	
170			streamServer := stream.Server{
171				Listen:     fmt.Sprintf("%d%s", server.Port, protocolSuffix),
172				StatusZone: fmt.Sprintf("%s_%d", protocol, server.Port),
173				ProxyPass:  proxyPass,
174			}
175			*streamServers = append(*streamServers, streamServer)
176			portSet[key] = struct{}{}
177		}
178	}
179	
180	func getRewriteClientIPSettingsForStream(
181		rewriteConfig dataplane.RewriteClientIPSettings,
182	) shared.RewriteClientIPSettings {
183		proxyEnabled := rewriteConfig.Mode == dataplane.RewriteIPModeProxyProtocol
184		if proxyEnabled {
185			return shared.RewriteClientIPSettings{
186				ProxyProtocol: shared.ProxyProtocolDirective,
187				RealIPFrom:    rewriteConfig.TrustedAddresses,
188			}
189		}
190	
191		return shared.RewriteClientIPSettings{}
192	}
193	
194	// createStreamSplitClients creates split_clients configurations for Layer4 servers with multiple backends.
195	func createStreamSplitClients(conf dataplane.Configuration) []stream.SplitClient {
196		var splitClients []stream.SplitClient
197	
198		// Process TCP servers
199		for _, server := range conf.TCPServers {
200			if server.NeedsWeightDistribution() {
201				splitClient := createSplitClientForL4Server(server)
202				if splitClient != nil {
203					splitClients = append(splitClients, *splitClient)
204				}
205			}
206		}
207	
208		// Process UDP servers
209		for _, server := range conf.UDPServers {
210			if server.NeedsWeightDistribution() {
211				splitClient := createSplitClientForL4Server(server)
212				if splitClient != nil {
213					splitClients = append(splitClients, *splitClient)
214				}
215			}
216		}
217	
218		return splitClients
219	}
220	
221	// createSplitClientForL4Server creates a split_clients configuration for a Layer4 server with multiple backends.
222	func createSplitClientForL4Server(server dataplane.Layer4VirtualServer) *stream.SplitClient {
223		if !server.NeedsWeightDistribution() {
224			return nil
225		}
226	
227		// Calculate total weight
228		totalWeight := int32(0)
229		for _, upstream := range server.Upstreams {
230			totalWeight += upstream.Weight
231		}
232	
233		if totalWeight == 0 {
234			return nil
235		}
236	
237		distributions := make([]stream.SplitClientDistribution, 0, len(server.Upstreams))
238		availablePercentage := float64(100)
239	
240		// Process all upstreams except the last one
241		for i := range len(server.Upstreams) - 1 {
242			upstream := server.Upstreams[i]
243			percentage := percentOf(upstream.Weight, totalWeight)
244			availablePercentage -= percentage
245	
246			distributions = append(distributions, stream.SplitClientDistribution{
247				Percent: fmt.Sprintf("%.2f", percentage),
248				Value:   upstream.Name,
249			})
250		}
251	
252		// The last upstream gets the remaining percentage
253		lastUpstream := server.Upstreams[len(server.Upstreams)-1]
254		distributions = append(distributions, stream.SplitClientDistribution{
255			Percent: fmt.Sprintf("%.2f", availablePercentage),
256			Value:   lastUpstream.Name,
257		})
258	
259		return &stream.SplitClient{
260			VariableName:  fmt.Sprintf("backend_%d", server.Port),
261			Distributions: distributions,
262		}
263	}
264	
265	// createTLSTerminateSocketServer creates stream socket servers for TLS Terminate mode.
266	// These servers terminate TLS and proxy the decrypted TCP traffic to upstreams.
267	func createTLSTerminateSocketServer(
268		server dataplane.Layer4VirtualServer,
269		upstreams map[string]dataplane.Upstream,
270		conf dataplane.Configuration,
271	) []stream.Server {
272		if server.IsDefault {
273			// Default server for TLS Terminate: reject TLS handshake for unmatched traffic.
274			// Empty hostname defaults reject when no routes match the listener.
275			// Named hostname defaults reject when SNI doesn't match.
276			// Both cases use ssl_reject_handshake to avoid creating non-functional servers.
277			return []stream.Server{
278				{
279					Listen:   getSocketNameTLSTerminate(server.Port, server.Hostname),
280					IsSocket: true,
281					SSL: &stream.SSL{
282						RejectHandshake: true,
283					},
284					RewriteClientIP: getRewriteClientIPSettingsForStream(
285						conf.BaseHTTPConfig.RewriteClientIPSettings,
286					),
287				},
288			}
289		}
290	
291		if len(server.Upstreams) == 0 || server.Hostname == "" {
292			return nil
293		}
294	
295		upstreamName := server.Upstreams[0].Name
296		u, ok := upstreams[upstreamName]
297		if !ok || len(u.Endpoints) == 0 {
298			return nil
299		}
300	
301		streamServer := stream.Server{
302			Listen:         getSocketNameTLSTerminate(server.Port, server.Hostname),
303			StatusZone:     server.Hostname,
304			ProxyPass:      upstreamName,
305			IsSocket:       true,
306			SSL:            buildStreamSSL(server.SSL),
307			ProxySSLVerify: buildStreamProxySSLVerify(server.VerifyTLS),
308		}
309		streamServer.RewriteClientIP = getRewriteClientIPSettingsForStream(
310			conf.BaseHTTPConfig.RewriteClientIPSettings,
311		)
312	
313		return []stream.Server{streamServer}
314	}
315	
316	func buildStreamProxySSLVerify(v *dataplane.VerifyTLS) *stream.ProxySSLVerify {
317		if v == nil {
318			return nil
319		}
320	
321		trustedCert := v.RootCAPath
322		if v.CertBundleID != "" {
323			trustedCert = generateCertBundleFileName(v.CertBundleID)
324		}
325	
326		return &stream.ProxySSLVerify{
327			TrustedCertificate: trustedCert,
328			Name:               v.Hostname,
329		}
330	}
331	
332	// buildStreamSSL converts a dataplane SSL config into a stream.SSL config,
333	// generating the PEM file paths for each certificate/key pair.
334	func buildStreamSSL(ssl *dataplane.SSL) *stream.SSL {
335		if ssl == nil {
336			return nil
337		}
338	
339		certs := make([]string, 0, len(ssl.KeyPairIDs))
340		keys := make([]string, 0, len(ssl.KeyPairIDs))
341	
342		for _, id := range ssl.KeyPairIDs {
343			pemFile := generatePEMFileName(id)
344			certs = append(certs, pemFile)
345			keys = append(keys, pemFile)
346		}
347	
348		return &stream.SSL{
349			Certificates:        certs,
350			CertificateKeys:     keys,
351			Protocols:           ssl.Protocols,
352			Ciphers:             ssl.Ciphers,
353			PreferServerCiphers: ssl.PreferServerCiphers,
354		}
355	}
